const trigger = $('workflow_trigger').first().json;
const genre = $('get_genre_config').first().json;
const genreData = Array.isArray(genre) ? genre[0] : genre;
const research = $('research_concept').first().json.message || '';
const chapterCount = parseInt(trigger.target_chapter_count) || 10;

const prompt = `You are a master storyteller and book architect.

## Genre: ${genreData?.genre_name || 'Fiction'}
## Genre Guidelines: ${genreData?.writing_guidelines || ''}

## Research
${research}

## Assignment
Create a detailed book outline for "${trigger.project_title || 'Untitled'}".

Core concept: ${trigger.initial_concept}
Themes: ${trigger.themes || 'To be determined'}
Target chapters: ${chapterCount}

## Requirements
Generate a comprehensive outline including:
1. A refined title and one-paragraph premise
2. Core themes (3-5)
3. Character profiles (at least 3 major characters) with name, role, character arc, and physical/personality description
4. Chapter-by-chapter breakdown (${chapterCount} chapters) with:
   - Chapter number and title
   - 2-3 sentence brief of what happens
   - Arc notes (character development, theme progression)
   - Research topics that should be explored for this chapter

Return as JSON matching the output schema exactly.`;

return [{ json: { prompt } }];

const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json', 'Prefer': 'return=representation' };
const trigger = $('workflow_trigger').first().json;
const outline = $input.first().json.output || {};
const title = outline.title || trigger.project_title || 'Untitled';
const genreSlug = trigger.genre_slug;

// Try to find existing project
let project = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects?title=eq.' + encodeURIComponent(title) + '&limit=1',
    headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey }
  });
  if (Array.isArray(resp) && resp.length > 0 && resp[0].id) project = resp[0];
} catch (e) {}

if (project) {
  // Update existing
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: supabaseUrl + '/rest/v1/writing_projects?id=eq.' + project.id,
    headers,
    body: { outline: outline, genre_slug: genreSlug, updated_at: new Date().toISOString() }
  });
} else {
  // Create new
  const created = await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/writing_projects',
    headers,
    body: { title, genre_slug: genreSlug, project_type: 'book', status: 'outlined', outline: outline, chapter_count: (outline.chapters || []).length }
  });
  project = Array.isArray(created) ? created[0] : created;
}

return [{ json: { outline, project_id: project?.id || null, title } }];
